struct Counter {
    values: Vec<i32>,
}

impl Counter {
    fn max_val(&self) -> Option<i32> {
        // Return owned i32 (Copy) instead of &i32 to end the borrow immediately
        self.values.iter().copied().max()
    }

    fn double_max(&mut self) {
        if let Some(m) = self.max_val() {
            self.values.push(m * 2);
        }
    }
}

fn main() {
    let mut c = Counter { values: vec![1, 3, 2, 5, 4] };
    c.double_max();
    println!("{:?}", c.values);
}

